import React, { useState, useEffect } from 'react';
import { View, Text, TouchableOpacity, Alert, Platform } from 'react-native';
import * as WebBrowser from 'expo-web-browser';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';

const AUTH_ENDPOINT = 'https://oauth2.example.com/auth';
const TOKEN_ENDPOINT = 'https://oauth2.example.com/token';
const CLIENT_ID = 'mobile_app_client_123';
const CLIENT_SECRET = 'secret_abc123xyz456';
const REDIRECT_URI = Platform.OS === 'android' 
  ? 'com.yourapp://oauth2redirect' 
  : 'com.yourapp://oauth2redirect';

const OAuth2Client = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    const loadTokens = async () => {
      try {
        const storedAccessToken = await SecureStore.getItemAsync('access_token');
        const storedRefreshToken = await SecureStore.getItemAsync('refresh_token');
        if (storedAccessToken) setAccessToken(storedAccessToken);
        if (storedRefreshToken) setRefreshToken(storedRefreshToken);
      } catch (error) {
        console.error('Failed to load tokens:', error);
      }
    };
    loadTokens();
  }, []);

  const startOAuthFlow = async () => {
    setIsLoading(true);
    try {
      const redirectUri = REDIRECT_URI;
      const authUrl = `${AUTH_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${redirectUri}&scope=read write`;
      
      const result = await WebBrowser.openAuthSessionAsync(authUrl, redirectUri);
      
      if (result.type === 'success' && result.url) {
        const url = new URL(result.url);
        const code = url.searchParams.get('code');
        
        if (code) {
          await exchangeCodeForToken(code);
        } else {
          throw new Error('Authorization code not found in URL');
        }
      }
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
    } finally {
      setIsLoading(false);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': `Basic ${btoa(`${CLIENT_ID}:${CLIENT_SECRET}`)}`
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: REDIRECT_URI
        })
      });

      const data = await response.json();
      
      if (!response.ok) {
        throw new Error(data.error || 'Token exchange failed');
      }

      if (data.access_token) {
        await SecureStore.setItemAsync('access_token', data.access_token);
        setAccessToken(data.access_token);
        
        if (data.refresh_token) {
          await SecureStore.setItemAsync('refresh_token', data.refresh_token);
          setRefreshToken(data.refresh_token);
        }
      }
    } catch (error) {
      throw new Error(`Token exchange failed: ${error.message}`);
    }
  };

  const refreshAccessToken = async () => {
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }
    
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': `Basic ${btoa(`${CLIENT_ID}:${CLIENT_SECRET}`)}`
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: refreshToken
        })
      });

      const data = await response.json();
      
      if (!response.ok) {
        throw new Error(data.error || 'Token refresh failed');
      }

      if (data.access_token) {
        await SecureStore.setItemAsync('access_token', data.access_token);
        setAccessToken(data.access_token);
      }
    } catch (error) {
      throw new Error(`Token refresh failed: ${error.message}`);
    }
  };

  const logout = async () => {
    try {
      await SecureStore.deleteItemAsync('access_token');
      await SecureStore.deleteItemAsync('refresh_token');
      setAccessToken(null);
      setRefreshToken(null);
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', padding: 20 }}>
      {accessToken ? (
        <View>
          <Text>Authenticated</Text>
          <TouchableOpacity onPress={logout} style={{ padding: 10, backgroundColor: 'red' }}>
            <Text style={{ color: 'white' }}>Logout</Text>
          </TouchableOpacity>
        </View>
      ) : (
        <TouchableOpacity 
          onPress={startOAuthFlow} 
          disabled={isLoading}
          style={{ padding: 15, backgroundColor: 'blue' }}
        >
          <Text style={{ color: 'white' }}>
            {isLoading ? 'Loading...' : 'Login with OAuth'}
          </Text>
        </TouchableOpacity>
      )}
    </View>
  );
};

export default OAuth2Client;